fn html_to_text(html: &str) -> String {
    html2text::from_read(html.as_bytes(), usize::MAX)
        .lines()
        .map(str::trim_end)
        .collect::<Vec<_>>()
        .join("\n")
        .trim()
        .to_string()
}

